// API Key authentication check - timing-safe comparison
const headers = $input.first().json.headers || {};

// Case-insensitive header lookup (defense against platform normalization changes)
const headerKeys = Object.keys(headers);
const apiKeyHeader = headerKeys.find(k => k.toLowerCase() === 'x-api-key');
const providedKey = apiKeyHeader !== undefined ? headers[apiKeyHeader] : $input.first().json.api_key;
const expectedKey = $env.RVC_API_KEY;

// Timing-safe comparison - constant time regardless of input length
function timingSafeEqual(a, b) {
  if (a == null || b == null) return false;
  const maxLen = Math.max(a.length, b.length);
  let result = a.length ^ b.length;
  for (let i = 0; i < maxLen; i++) {
    const charA = i < a.length ? a.charCodeAt(i) : 0;
    const charB = i < b.length ? b.charCodeAt(i) : 0;
    result |= charA ^ charB;
  }
  return result === 0;
}

if (expectedKey && !timingSafeEqual(providedKey || '', expectedKey)) {
  throw new Error('Authentication failed');
}

const input = $input.first().json || {};
const model = input.model || '';
const audioPath = input.audio_path || '';
const audio = input.audio || '';

// === ENHANCED PATH TRAVERSAL PROTECTION ===
// Blocks: ../, ..\, %2e%2e, %252e%252e (double encoded), \x5c, \x2e, null bytes, absolute paths
const pathTraversalPattern = /(\.\.[/\\]|%2e%2e[/\\]|%252e%252e|\\x5c|\\x2e|%00|\\x00|^\/|^[a-zA-Z]:\\)/i;

// Decode and normalize for Unicode NFC attack detection
let normalizedPath;
try {
  normalizedPath = decodeURIComponent(audioPath).normalize('NFC');
} catch (e) {
  throw new Error('Invalid audio_path: malformed URL encoding');
}

// === MODEL VALIDATION ===
const validModelPattern = /^[a-zA-Z0-9_-]+$/;

// === F0_METHOD ALLOWLIST ===
const validF0Methods = ['harvest', 'pm', 'dio', 'rmvpe', 'crepe', 'crepe-tiny', 'mangio-crepe', 'mangio-crepe-tiny'];
const f0Method = (input.f0_method || 'rmvpe').toLowerCase();

// === PITCH VALIDATION ===
const pitch = parseInt(input.pitch, 10) || 0;
if (pitch < -12 || pitch > 12) {
  throw new Error('Invalid pitch: must be between -12 and +12 semitones');
}

// === REQUIRED FIELD CHECKS ===
if (!model) {
  throw new Error('Missing required field: model');
}
if (!audio && !audioPath) {
  throw new Error('Missing required field: audio or audio_path');
}

// === PATH VALIDATION ===
if (audioPath) {
  if (pathTraversalPattern.test(audioPath) || pathTraversalPattern.test(normalizedPath)) {
    throw new Error('Path traversal detected: audio_path contains invalid sequences');
  }
}

// === MODEL VALIDATION ===
if (!validModelPattern.test(model)) {
  throw new Error('Invalid model name: must be alphanumeric, dash, or underscore only');
}
if (model.length > 100) {
  throw new Error('Model name too long: max 100 characters');
}

// === F0_METHOD VALIDATION ===
if (!validF0Methods.includes(f0Method)) {
  throw new Error('Invalid f0_method: must be one of ' + validF0Methods.join(', '));
}

return [{
  json: {
    model: model,
    audio: audio,
    audio_path: audioPath,
    channel: input.channel || '#general',
    pitch: pitch,
    f0_method: f0Method
  }
}];

